DESCRIPTION = '冷蔵庫の食材を無料で管理。賞味期限が近い食材を自動警告。食材から使えるレシピ候補を提案。買い物リスト生成機能付き。登録不要でスマホに保存。'
JS_CODE = 'const STORE = \'fridge_v1\';\nconst SHOP_STORE = \'fridge_shop_v1\';\n\nconst CATEGORIES = [\n    { id: \'veg\', label: \'野菜\', emoji: \'🥦\' },\n    { id: \'meat\', label: \'肉類\', emoji: \'🥩\' },\n    { id: \'fish\', label: \'魚介\', emoji: \'🐟\' },\n    { id: \'dairy\', label: \'乳製品\', emoji: \'🥛\' },\n    { id: \'egg\', label: \'卵\', emoji: \'🥚\' },\n    { id: \'fruit\', label: \'果物\', emoji: \'🍎\' },\n    { id: \'seasoning\', label: \'調味料\', emoji: \'🧂\' },\n    { id: \'frozen\', label: \'冷凍食品\', emoji: \'🧊\' },\n    { id: \'drink\', label: \'飲み物\', emoji: \'🧃\' },\n    { id: \'bread\', label: \'パン・麺\', emoji: \'🍞\' },\n    { id: \'snack\', label: \'お菓子\', emoji: \'🍫\' },\n    { id: \'other\', label: \'その他\', emoji: \'🫙\' },\n];\n\nconst RECIPES = [\n    { name: \'野菜炒め\', needs: [\'veg\', \'meat\'], label: \'野菜と肉があれば\' },\n    { name: \'オムレツ\', needs: [\'egg\', \'dairy\'], label: \'卵と乳製品で\' },\n    { name: \'魚の塩焼き\', needs: [\'fish\', \'seasoning\'], label: \'魚と調味料で\' },\n    { name: \'サラダ\', needs: [\'veg\', \'fruit\'], label: \'野菜・果物で\' },\n    { name: \'炒飯\', needs: [\'egg\', \'veg\', \'meat\'], label: \'卵・野菜・肉で\' },\n    { name: \'スムージー\', needs: [\'fruit\', \'dairy\'], label: \'果物と乳製品で\' },\n    { name: \'シチュー\', needs: [\'meat\', \'veg\', \'dairy\'], label: \'肉・野菜・乳製品で\' },\n    { name: \'魚介のパスタ\', needs: [\'fish\', \'bread\', \'seasoning\'], label: \'魚介・麺・調味料で\' },\n];\n\nlet selectedCat = \'veg\';\nlet activeFilter = \'all\';\n\nfunction getFoods() { try { return JSON.parse(localStorage.getItem(STORE)||\'[]\'); } catch(e){return[];} }\nfunction setFoods(d) { try { localStorage.setItem(STORE, JSON.stringify(d)); } catch(e){} }\nfunction getShop() { try { return JSON.parse(localStorage.getItem(SHOP_STORE)||\'[]\'); } catch(e){return[];} }\nfunction setShop(d) { try { localStorage.setItem(SHOP_STORE, JSON.stringify(d)); } catch(e){} }\n\nfunction daysUntil(dateStr) {\n    if (!dateStr) return 999;\n    const today = new Date(); today.setHours(0,0,0,0);\n    const exp = new Date(dateStr);\n    return Math.round((exp - today) / 86400000);\n}\n\nfunction expiryStatus(days) {\n    if (days < 0) return \'expired\';\n    if (days === 0) return \'today\';\n    if (days <= 3) return \'soon\';\n    return \'ok\';\n}\n\nfunction expiryLabel(days, dateStr) {\n    if (!dateStr) return \'期限未設定\';\n    if (days < 0) return `${Math.abs(days)}日超過`;\n    if (days === 0) return \'本日期限\';\n    if (days <= 3) return `あと${days}日`;\n    return `あと${days}日`;\n}\n\nfunction buildCatGrid() {\n    const grid = document.getElementById(\'cat-grid\');\n    grid.innerHTML = CATEGORIES.map(c => `\n        <button class="cat-btn ${c.id === selectedCat ? \'selected\' : \'\'}" onclick="selectCat(\'${c.id}\',this)">\n            <span>${c.emoji}</span>${c.label}\n        </button>`).join(\'\');\n}\n\nfunction selectCat(id, el) {\n    selectedCat = id;\n    document.querySelectorAll(\'.cat-btn\').forEach(b => b.classList.remove(\'selected\'));\n    el.classList.add(\'selected\');\n}\n\nfunction openModal(editId) {\n    document.getElementById(\'edit-id\').value = editId || \'\';\n    document.getElementById(\'modal-title\').textContent = editId ? \'食材を編集\' : \'食材を追加\';\n    if (editId) {\n        const food = getFoods().find(f => f.id === editId);\n        if (food) {\n            selectedCat = food.cat;\n            document.getElementById(\'f-name\').value = food.name;\n            document.getElementById(\'f-qty\').value = food.qty || \'\';\n            document.getElementById(\'f-expiry\').value = food.expiry || \'\';\n            document.getElementById(\'f-location\').value = food.location || \'冷蔵\';\n        }\n    } else {\n        selectedCat = \'veg\';\n        document.getElementById(\'f-name\').value = \'\';\n        document.getElementById(\'f-qty\').value = \'\';\n        document.getElementById(\'f-expiry\').value = \'\';\n        document.getElementById(\'f-location\').value = \'冷蔵\';\n        // 今日+7日をデフォルト\n        const d = new Date(); d.setDate(d.getDate() + 7);\n        document.getElementById(\'f-expiry\').value = d.toISOString().slice(0,10);\n    }\n    buildCatGrid();\n    document.getElementById(\'modal-overlay\').classList.add(\'open\');\n}\n\nfunction closeModal() {\n    document.getElementById(\'modal-overlay\').classList.remove(\'open\');\n}\n\nfunction save'
